// sort, heap, greedy
class Solution {
public:
    int maxRemoval(vector<int>& nums, vector<vector<int>>& queries) {
        sort(begin(queries), end(queries), greater<vector<int>>());
        priority_queue<int, vector<int>> max_heap;   
        priority_queue<int, vector<int>, greater<int>> min_heap;
        for (int i = 0; i < size(nums); ++i) {
            while (!empty(queries) && queries.back()[0] <= i) {
                max_heap.emplace(queries.back()[1]);
                queries.pop_back();
            }
            while (!empty(min_heap) && min_heap.top() < i) {
                min_heap.pop();
            }
            while (size(min_heap) < nums[i]) {
                if (empty(max_heap) || max_heap.top() < i) {
                    return -1;
                }
                min_heap.emplace(max_heap.top());
                max_heap.pop();
            }
        }
        return size(max_heap);
    }
};

# Time:  O(n + qlogq)
# Space: O(q)

import heapq


# sort, heap, greedy
class Solution(object):
    def maxRemoval(self, nums, queries):
        """
        :type nums: List[int]
        :type queries: List[List[int]]
        :rtype: int
        """
        queries.sort(reverse=True)
        max_heap, min_heap = [], []
        for i in xrange(len(nums)):
            while queries and queries[-1][0] <= i:
                heapq.heappush(max_heap, -queries.pop()[1])
            while min_heap and min_heap[0] < i:
                heapq.heappop(min_heap)
            while len(min_heap) < nums[i]:
                if not max_heap or -max_heap[0] < i:
                    return -1
                heapq.heappush(min_heap, -heapq.heappop(max_heap))
        return len(max_heap)
